<template><div class="panel"><div class="section-head"><div><h2>{{ t('providers.title') }}</h2><p>{{ t('providers.description') }}</p></div><el-button v-if="auth.hasPermission('model:provider:create')" type="primary" @click="open()">{{ t('providers.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="code" :label="t('common.code')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column prop="baseUrl" :label="t('providers.baseUrl')"/><el-table-column prop="concurrencyLevel" :label="t('providers.concurrencyLevel')"/><el-table-column prop="concurrencyLimit" :label="t('providers.concurrency')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button v-if="auth.hasPermission('model:provider:update')" link type="primary" @click="viewKeys(s.row)">{{ t('providers.viewKeys') }}</el-button><el-button v-if="auth.hasPermission('model:provider:update')" link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click="remove(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('providers.edit'):t('providers.add')" width="620px"><el-form label-width="100px"><el-form-item :label="t('common.code')"><el-input v-model="form.code"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item label="Base URL"><el-input v-model="form.baseUrl"/></el-form-item><el-form-item :label="t('providers.apiKeys')"><div v-for="(_,index) in keyRows" :key="index" class="api-key-editor-row"><el-input v-model="keyRows[index]" :placeholder="t('providers.keyPlaceholder')"/><el-button link type="danger" @click="deleteKey(index)">{{ t('providers.deleteKey') }}</el-button></div><el-button plain type="primary" @click="addKey">+ {{ t('providers.addKey') }}</el-button></el-form-item><el-form-item :label="t('providers.concurrencyLevel')"><el-select v-model="form.concurrencyLevel"><el-option :label="t('providers.provider')" value="PROVIDER"/><el-option label="API Key" value="API_KEY"/></el-select></el-form-item><el-form-item :label="t('providers.concurrency')"><el-input-number v-model="form.concurrencyLimit" :min="1"/></el-form-item><el-form-item :label="t('providers.timeout')"><el-input-number v-model="form.timeoutSeconds" :min="1"/></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog><el-dialog v-model="keysVisible" :title="t('providers.viewKeys')" width="520px"><div v-for="(key,index) in keysContent" :key="key" class="api-key-row"><code>{{ index + 1 }}. {{ key }}</code><el-button link type="primary" @click="copyKey(key)">{{ t('providers.copyKey') }}</el-button></div></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';import{useAuthStore}from'../stores/auth';import{copyApiKey,normalizeApiKeys,serializeApiKeyRows,splitApiKeys,toApiKeyRows}from'../utils/apiKeys';const{t}=useI18n();const auth=useAuthStore(),rows=ref([]),visible=ref(false),keysVisible=ref(false),keysContent=ref([]),keyRows=ref(['']),form=reactive({id:null,code:'',name:'',baseUrl:'',apiKeys:'',concurrencyLimit:4,concurrencyLevel:'PROVIDER',timeoutSeconds:60,enabled:true});async function load(){rows.value=(await http.get('/models/providers')).data}/** 获取并规范化指定供应商的明文 API Key。 */async function loadKeys(id){return normalizeApiKeys((await http.get(`/models/providers/${id}/api-keys`)).data.apiKeys)}/** 打开供应商窗口，编辑时回显全部 API Key。 */async function open(row){if(row){Object.assign(form,{...row,apiKeys:''});keyRows.value=toApiKeyRows(await loadKeys(row.id))}else{Object.assign(form,{id:null,code:'',name:'',baseUrl:'',apiKeys:'',concurrencyLimit:4,concurrencyLevel:'PROVIDER',timeoutSeconds:60,enabled:true});keyRows.value=['']}visible.value=true}/** 新增一行可填写的 API Key。 */function addKey(){keyRows.value.push('')}/** 删除指定的 API Key 输入行。 */function deleteKey(index){keyRows.value.splice(index,1)}/** 查看供应商的明文 API Key。 */async function viewKeys(row){keysContent.value=splitApiKeys(await loadKeys(row.id));keysVisible.value=true}/** 复制单个 API Key 并提示操作结果。 */async function copyKey(key){try{await copyApiKey(key);ElMessage.success(t('providers.keyCopied'))}catch{ElMessage.error(t('providers.copyFailed'))}}/** 保存供应商。 */async function save(){form.apiKeys=serializeApiKeyRows(keyRows.value);form.id?await http.put(`/models/providers/${form.id}`,form):await http.post('/models/providers',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}/** 删除供应商。 */async function remove(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.name}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/models/providers/${row.id}`);await load();ElMessage.success(t('common.successDeleted'))}onMounted(load)</script>
